<script setup>
import { Head, Link } from '@inertiajs/vue3'; import axios from 'axios'; import { ref } from 'vue'; import Swal from 'sweetalert2';
const props=defineProps({preferences:{type:Array,default:()=>[]}}); const items=ref(JSON.parse(JSON.stringify(props.preferences))); const saving=ref(false); const labels={task:'Aufgaben und Fristen',application:'Bewerbungsschritte',course:'Kursbeginn',course_session:'Kurstermine',message:'Nachrichten'};
const save=async()=>{saving.value=true;try{const r=await axios.put(route('participant-portal.notification-preferences.update'),{preferences:items.value});items.value=r.data.preferences;Swal.fire('Gespeichert',r.data.message,'success');}catch(e){Swal.fire('Fehler',e.response?.data?.message||'Einstellungen konnten nicht gespeichert werden.','error');}finally{saving.value=false;}};
</script>
<template><Head title="Benachrichtigungseinstellungen"/><main class="min-h-screen bg-slate-50 px-6 py-8"><div class="mx-auto max-w-4xl"><div class="flex items-center justify-between"><div><p class="text-xs font-semibold uppercase tracking-widest text-zbb">Teilnehmerportal</p><h1 class="text-2xl font-bold">Benachrichtigungen</h1><p class="text-sm text-slate-500">Legen Sie fest, welche Hinweise im Portal und per E-Mail erscheinen.</p></div><Link :href="route('participant-portal.dashboard')" class="rounded border bg-white px-4 py-2 text-sm">Zur Übersicht</Link></div><div class="mt-6 overflow-hidden rounded-2xl border bg-white shadow-sm"><div v-for="item in items" :key="item.category" class="grid items-center gap-4 border-b p-5 last:border-b-0 md:grid-cols-[1fr_140px_140px_170px]"><div><p class="font-semibold">{{ labels[item.category] }}</p><p class="text-xs text-slate-500">Für alle eigenen Projektteilnahmen</p></div><label class="flex gap-2 text-sm"><input v-model="item.in_app_enabled" type="checkbox"/>Im Portal</label><label class="flex gap-2 text-sm"><input v-model="item.email_enabled" type="checkbox"/>Per E-Mail</label><label class="text-xs text-slate-500">Vorlauf in Tagen<input v-model.number="item.days_before" type="number" min="0" max="30" class="mt-1 w-full rounded border-slate-300 text-sm" :disabled="item.category==='message'"/></label></div></div><button class="mt-5 rounded bg-zbb px-5 py-2.5 font-semibold text-white disabled:opacity-50" :disabled="saving" @click="save">{{ saving?'Speichert …':'Einstellungen speichern' }}</button></div></main></template>
